export const getExportDossierUrl = (farmId: number,
    params: ExportDossierParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/farms/${farmId}/certification/export-dossier?${stringifiedParams}` : `/api/v1/farms/${farmId}/certification/export-dossier`
}

